-- Leverancier-koppeling op BTW-nummer (deterministisch; de rest volgt in
-- een verzoeningsronde). Proximus, Mega Telco (v/h Power Online), Close Call.
UPDATE kosten.octopus_relatie SET leverancier_id =
    (SELECT id FROM kern.leverancier WHERE naam ILIKE '%proximus%' ORDER BY naam LIMIT 1)
 WHERE btw_nummer = 'BE0202.239.951' AND leverancier_id IS NULL;
UPDATE kosten.octopus_relatie SET leverancier_id =
    (SELECT id FROM kern.leverancier WHERE naam ILIKE '%mega%' ORDER BY naam LIMIT 1)
 WHERE btw_nummer IN ('BE0788.562.092', 'BE0535.615.192') AND leverancier_id IS NULL;
UPDATE kosten.octopus_relatie SET leverancier_id =
    (SELECT id FROM kern.leverancier WHERE naam ILIKE '%xelion%' OR naam ILIKE '%close call%' ORDER BY naam LIMIT 1)
 WHERE btw_nummer = 'BE0799.782.024' AND leverancier_id IS NULL;

-- Interne relaties: de naam bevat de naam van een eigen firma (minimaal
-- 4 tekens om valse treffers te vermijden).
UPDATE kosten.octopus_relatie o SET is_intern = true
 WHERE EXISTS (SELECT 1 FROM kern.firma f
        WHERE length(f.naam) >= 4
          AND (lower(o.naam) LIKE '%' || lower(f.naam) || '%'
               OR lower(o.zoekveld) LIKE '%' || lower(f.naam) || '%'));

-- Controle
SELECT firma_code, count(*) AS relaties,
       count(*) FILTER (WHERE is_klant) AS klanten,
       count(*) FILTER (WHERE is_leverancier) AS leveranciers,
       count(*) FILTER (WHERE is_intern) AS intern,
       count(*) FILTER (WHERE leverancier_id IS NOT NULL) AS gekoppeld
  FROM kosten.octopus_relatie GROUP BY firma_code ORDER BY firma_code;
